const { ethers } = require("ethers");

const provider = new ethers.providers.Web3Provider(window.ethereum);
let signer;

async function connectWallet() {
    await provider.send("eth_requestAccounts", []);
    signer = provider.getSigner();
}

async function sendTransaction(contractAddress, abi, methodName, params) {
    const contract = new ethers.Contract(contractAddress, abi, signer);
    try {
        const tx = await contract[methodName](...params);
        await tx.wait();
        console.log("Transaction successful:", tx);
    } catch (error) {
        console.error("Transaction failed:", error);
    }
}

function validateInput(input) {
    // Implement input validation logic here
    // Example: Check if input is a valid Ethereum address or number
    return ethers.utils.isAddress(input);
}

document.getElementById("connectButton").addEventListener("click", connectWallet);

document.getElementById("sendButton").addEventListener("click", async () => {
    const contractAddress = document.getElementById("contractAddress").value;
    const abi = JSON.parse(document.getElementById("abi").value);
    const methodName = document.getElementById("methodName").value;
    const params = JSON.parse(document.getElementById("params").value);

    if (!validateInput(contractAddress) || !methodName) {
        alert("Invalid input");
        return;
    }

    await sendTransaction(contractAddress, abi, methodName, params);
});